mapper.update:
update board set btitle = #{btitle}, bcontent = #{bcontent}, bdate = #{bdate}, bwriter = #{bwriter},
battachoname = #{battachoname}, bhintcount = #{bhintcount}, battachsname = #{battachsname}, battachtype = #{battachtype}, battachdata = #{battachdata}
where bno = #{bno}

mapper.select:
select bno, btitle, bcontent, bdate, bwriter, bhintcount, battachoname, battachsname, battachtype, battachdata
from board
where bno = #{value}
